/** Get DIP switch definition for a game. Tries exact match, then prefix fallback. */
export function getDipDef(gameName: string): DipSwitchDef {
  if (GAME_DIPS[gameName]) return GAME_DIPS[gameName];
  // Try prefix match: sf2hf → sf2, sf2ce → sf2, etc.
  const keys = Object.keys(GAME_DIPS);
  // Sort by length descending so longer matches win (sf2ce before sf2)
  keys.sort((a, b) => b.length - a.length);
  for (const key of keys) {
    if (gameName.startsWith(key)) return GAME_DIPS[key]!;
  }
  return { switches: [] };
}

/** Map bank letter to ioPorts index */
export function bankToIndex(bank: "A" | "B" | "C"): number {
  switch (bank) {
    case "A": return 10;
    case "B": return 12;
    case "C": return 14;
  }
}
